SELECT title, event_description
FROM events
WHERE event_id IN (SELECT event_id FROM ratings WHERE rating_value = 5);

SELECT event_id, event_type, title, event_description, speaker 
FROM events 
WHERE event_id IN (
  SELECT event_id 
  FROM ratings 
  WHERE rating_value = (
    SELECT MAX(rating_value) 
    FROM ratings
  )
);

SELECT event_id, platform, media_url, media_format
FROM media_links
WHERE event_id = 1;
